func retry(maxAttempts int, delay time.Duration, op func() error) error {
	var err error
	for i := range maxAttempts {
		err = op()
		if err == nil {
			return nil
		}
		if i < maxAttempts-1 {
			time.Sleep(delay)
		}
	}
	return fmt.Errorf("after %d attempts: %w", maxAttempts, err)
}

func chunk[T any](s []T, n int) [][]T {
	if n <= 0 {
		panic("chunk size must be positive")
	}
	var chunks [][]T
	for len(s) > 0 {
		k := min(n, len(s))
		chunks = append(chunks, s[:k:k])
		s = s[k:]
	}
	return chunks
}

func workerPool[J, R any](ctx context.Context, jobs <-chan J, workers int, fn func(J) R) []R {
	results := make(chan R, workers)
	var wg sync.WaitGroup
	for range workers {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for j := range jobs {
				results <- fn(j)
			}
		}()
	}
	go func() {
		wg.Wait()
		close(results)
	}()
	var out []R
	for r := range results {
		out = append(out, r)
	}
	return out
}

func fanOut[T any](in <-chan T, n int) []<-chan T {
	outs := make([]chan T, n)
	for i := range outs {
		outs[i] = make(chan T, cap(in))
	}
	go func() {
		defer func() {
			for _, ch := range outs {
				close(ch)
			}
		}()
		for v := range in {
			for _, ch := range outs {
				ch <- v
			}
		}
	}()
	result := make([]<-chan T, n)
	for i, ch := range outs {
		result[i] = ch
	}
	return result
}

